'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { cn } from '@/lib/utils';
import {
    Users,
    Building2,
    Database,
    DollarSign,
    FileText,
    BarChart2,
    Shield,
    Settings,
    LayoutDashboard
} from 'lucide-react';

const menuItems = [
    { href: '/admin', label: 'Dashboard', icon: LayoutDashboard },
    { href: '/admin/users', label: 'Usuários', icon: Users },
    { href: '/admin/clinics', label: 'Clínicas', icon: Building2 },
    { href: '/admin/database', label: 'Database', icon: Database },
    { href: '/admin/financial', label: 'Financeiro', icon: DollarSign },
    { href: '/admin/logs', label: 'Logs', icon: FileText },
    { href: '/admin/metrics', label: 'Métricas', icon: BarChart2 },
    { href: '/admin/security', label: 'Segurança', icon: Shield },
    { href: '/admin/settings', label: 'Configurações', icon: Settings },
];

export function AdminSidebar() {
    const pathname = usePathname();

    return (
        <aside className="w-64 bg-card border-r min-h-screen p-4">
            <div className="mb-8">
                <h2 className="text-xl font-bold text-primary">Admin Portal</h2>
                <p className="text-sm text-muted-foreground">Gerenciamento da plataforma</p>
            </div>

            <nav className="space-y-1">
                {menuItems.map((item) => {
                    const isActive = pathname === item.href ||
                        (item.href !== '/admin' && pathname?.startsWith(item.href));

                    return (
                        <Link
                            key={item.href}
                            href={item.href}
                            className={cn(
                                'flex items-center gap-3 px-3 py-2 rounded-lg text-sm transition-colors',
                                isActive
                                    ? 'bg-primary text-primary-foreground'
                                    : 'text-muted-foreground hover:bg-muted hover:text-foreground'
                            )}
                        >
                            <item.icon className="h-4 w-4" />
                            {item.label}
                        </Link>
                    );
                })}
            </nav>

            <div className="mt-8 pt-8 border-t">
                <Link
                    href="/"
                    className="flex items-center gap-2 px-3 py-2 text-sm text-muted-foreground hover:text-foreground transition-colors"
                >
                    ← Voltar ao App
                </Link>
            </div>
        </aside>
    );
}
